import os
import shutil
from zipfile import ZipFile
from tarfile import TarFile, GzipFile, BZ2File

def backup_directory(source_dir, format_type='tar.gz'):
    if not os.path.exists(source_dir):
        print(f"Directory {source_dir} does not exist.")
        return
    
    base_name = os.path.basename(source_dir)
    output_file = f"{base_name}.{format_type}"
    
    if format_type == 'tar.gz':
        with TarFile.open(output_file, "w:gz") as tar:
            tar.add(source_dir, arcname=os.path.basename(source_dir))
    elif format_type == 'tar.bz2':
        with TarFile.open(output_file, "w:bz2") as tar:
            tar.add(source_dir, arcname=os.path.basename(source_dir))
    elif format_type == 'zip':
        with ZipFile(output_file, 'w') as zipf:
            for root, dirs, files in os.walk(source_dir):
                for file in files:
                    zipf.write(os.path.join(root, file), os.path.relpath(os.path.join(root, file), start=source_dir))
    elif format_type == '7z':
        try:
            import py7zr
            with py7zr.SevenZipFile(output_file, mode='w') as z:
                for root, dirs, files in os.walk(source_dir):
                    for file in files:
                        z.write(os.path.join(root, file), os.path.relpath(os.path.join(root, file), start=source_dir))
        except ImportError:
            print("7z support requires py7zr library. Please install it using pip.")
            return
    else:
        print(f"Unsupported format: {format_type}")
        return
    
    print(f"Backup created successfully as {output_file}")

